/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// This method will execute report run controller for ETGSalesPackingSlip ETGReportFR
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{

    CustPackingSlipJour          custPackingSlipJour;
    SrsReportRunController       reportRunController;
    SrsReportRunImpl             srsReportRun;
    SalesPackingSlipContract     dataContract;

    if(_args.record() && _args.dataset() == tableNum(CustPackingSlipJour))
    {
        custPackingSlipJour = _args.record();
    }
    else
    {
        throw Error(Error::missingFormActiveBuffer(formStr(CustPackingSlipJournal)));
    }

    reportRunController = new SrsReportRunController();
    dataContract = new   SalesPackingSlipContract();
    reportRunController.parmReportName(ssrsReportStr(ETGSalesPackingSlip, ETGReport1FR));
    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as SalesPackingSlipContract;
    dataContract.parmRecordId(custPackingSlipJour.RecId);
    dataContract.parmTableId(custPackingSlipJour.TableId);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmShowDialog(false);
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmDialogCaption('packing slip report - French');
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();
}
